1738 /// Matches instructions with Opcode and any number of operands
1739 template <unsigned Opcode, typename... OperandTypes> struct AnyOps_match {
1740   std::tuple<OperandTypes...> Operands;
1741 
1742   AnyOps_match(const OperandTypes &...Ops) : Operands(Ops...) {}
1743 
1744   // Operand matching works by recursively calling match_operands, matching the
1745   // operands left to right. The first version is called for each operand but
1746   // the last, for which the second version is called. The second version of
1747   // match_operands is also used to match each individual operand.
1748   template <int Idx, int Last>
1749   std::enable_if_t<Idx != Last, bool> match_operands(const Instruction *I) {
1750     return match_operands<Idx, Idx>(I) && match_operands<Idx + 1, Last>(I);
1751   }
1752 
1753   template <int Idx, int Last>
1754   std::enable_if_t<Idx == Last, bool> match_operands(const Instruction *I) {
1755     return std::get<Idx>(Operands).match(I->getOperand(Idx));
1756   }
1757 
1758   template <typename OpTy> bool match(OpTy *V) {
1759     if (V->getValueID() == Value::InstructionVal + Opcode) {
1760       auto *I = cast<Instruction>(V);
1761       return I->getNumOperands() == sizeof...(OperandTypes) &&
1762              match_operands<0, sizeof...(OperandTypes) - 1>(I);
1763     }
1764     return false;
1765   }
1766 };
