1560 template <typename LHS_t, typename RHS_t, typename Class,
1561           bool Commutable = false>
1562 struct CmpClass_match {
1563   CmpPredicate *Predicate;
1564   LHS_t L;
1565   RHS_t R;
1566 
1567   // The evaluation order is always stable, regardless of Commutability.
1568   // The LHS is always matched first.
1569   CmpClass_match(CmpPredicate &Pred, const LHS_t &LHS, const RHS_t &RHS)
1570       : Predicate(&Pred), L(LHS), R(RHS) {}
1571   CmpClass_match(const LHS_t &LHS, const RHS_t &RHS)
1572       : Predicate(nullptr), L(LHS), R(RHS) {}
1573 
1574   template <typename OpTy> bool match(OpTy *V) {
1575     if (auto *I = dyn_cast<Class>(V)) {
1576       if (L.match(I->getOperand(0)) && R.match(I->getOperand(1))) {
1577         if (Predicate)
1578           *Predicate = CmpPredicate::get(I);
1579         return true;
1580       }
1581       if (Commutable && L.match(I->getOperand(1)) &&
1582           R.match(I->getOperand(0))) {
1583         if (Predicate)
1584           *Predicate = CmpPredicate::getSwapped(I);
1585         return true;
1586       }
1587     }
1588     return false;
1589   }
